1	import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
2	import { MemoryRouter } from "react-router-dom";
3	import { SessionProvider } from "@/features/session/context";
4	import { render, type RenderOptions } from "@testing-library/react";
5	import type { ReactElement, ReactNode } from "react";
6	
7	function createTestQueryClient() {
8	  return new QueryClient({
9	    defaultOptions: {
10	      queries: { retry: false, gcTime: 0 },
11	      mutations: { retry: false },
12	    },
13	  });
14	}
15	
16	function TestProviders({ children }: { children: ReactNode }) {
17	  const qc = createTestQueryClient();
18	  return (
19	    <QueryClientProvider client={qc}>
20	      <SessionProvider>
21	        <MemoryRouter>{children}</MemoryRouter>
22	      </SessionProvider>
23	    </QueryClientProvider>
24	  );
25	}
26	
27	export function renderWithProviders(
28	  ui: ReactElement,
29	  options?: Omit<RenderOptions, "wrapper">,
30	) {
31	  return render(ui, { wrapper: TestProviders, ...options });
32	}
