12	}
13	
14	export function VariableRow({ marketId, targetMarket }: VariableRowProps) {
15	  const { data } = useMarket(marketId);
16	  const { session, isConfigured } = useSession();
17	  const { addAssumption, removeAssumption, hasAssumption, getAssumption, contextPayload } = useAssumptions();
18	  const mutation = useProbabilityEdit(targetMarket.id);
19	
20	  const [editingOutcomeId, setEditingOutcomeId] = useState<string | null>(null);
21	  const [editValue, setEditValue] = useState(0.5);
22	
23	  if (!data) return null;
24	
25	  const m = data.market;
26	  const isAssumed = hasAssumption(m.id);
27	  const assumption = getAssumption(m.id);
28	  const isTargetMarket = m.id === targetMarket.id;
29	
30	  const handleAssume = (outcomeId: string) => {
31	    if (isAssumed && assumption?.outcomeId === outcomeId) {
32	      removeAssumption(m.id);
33	    } else {
34	      addAssumption({
35	        variableId: m.variableId,
36	        outcomeId,
37	        label: m.title,
38	      });
39	    }
40	  };
41	
42	  const handleStartEdit = (outcomeId: string, currentP: number) => {
43	    setEditingOutcomeId(outcomeId);
44	    setEditValue(currentP);
45	  };
46	
47	  const handleSubmitEdit = () => {
48	    if (!editingOutcomeId || !isConfigured) return;
49	    mutation.mutate({
50	      payload: {
51	        accountId: session.accountId,
52	        variableId: isTargetMarket ? targetMarket.variableId : m.variableId,
53	        target: { kind: "marginal", outcomeId: editingOutcomeId, probability: editValue },
54	        context: contextPayload,
55	        idempotencyKey: crypto.randomUUID(),
56	      },
57	      session,
58	    });
59	    setEditingOutcomeId(null);
60	  };
61	
62	  return (
63	    <div style={{
64	      ...rowStyle,
65	      ...(isAssumed ? assumedRowStyle : {}),
66	      ...(isTargetMarket ? targetRowStyle : {}),
67	    }}>
68	      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 4 }}>
69	        <span style={{ fontSize: "0.85rem", fontWeight: isTargetMarket ? 700 : 500 }}>
70	          {m.title}
71	          {isTargetMarket && <span style={{ fontSize: "0.7rem", color: "var(--color-primary)", marginLeft: 6 }}>(current)</span>}
72	        </span>
73	        {isAssumed && (
74	          <span style={assumedBadge}>
75	            ASSUMED: {assumption?.outcomeId}
76	          </span>
77	        )}
78	      </div>
79	
80	      <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
81	        {m.outcomes.map((o) => {
82	          const p = m.marginals[o.id] ?? 0;
83	          const isEditing = editingOutcomeId === o.id;
84	          const isThisAssumed = isAssumed && assumption?.outcomeId === o.id;
85	
86	          return (
87	            <div key={o.id} style={{ flex: 1, minWidth: 100 }}>
88	              {/* Probability display + inline bar */}
89	              <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
90	                <div style={{ flex: 1 }}>
91	                  <div style={{ height: 20, borderRadius: 4, background: "var(--color-border)", overflow: "hidden", position: "relative" }}>
92	                    <div style={{
93	                      height: "100%",
94	                      width: `${(isEditing ? editValue : p) * 100}%`,
95	                      borderRadius: 4,
96	                      background: isThisAssumed ? "var(--color-primary)" : p > 0.5 ? "var(--color-success)" : "var(--color-info)",
97	                      opacity: isAssumed && !isThisAssumed ? 0.3 : 0.7,
98	                      transition: "width 0.2s ease",
99	                    }} />
100	                    <span style={{
101	                      position: "absolute",
102	                      top: 2,
103	                      left: 6,
104	                      fontSize: "0.7rem",
105	                      fontWeight: 600,
106	                      color: "var(--color-text)",
107	                    }}>
108	                      {o.name}: {formatProbability(isEditing ? editValue : p)}
109	                    </span>
110	                  </div>
111	                </div>
112	              </div>
113	
114	              {/* Action buttons */}
115	              <div style={{ display: "flex", gap: 4 }}>
116	                {!isTargetMarket && (
117	                  <button
118	                    onClick={() => handleAssume(o.id)}
119	                    style={{
120	                      ...actionBtnStyle,
121	                      background: isThisAssumed ? "var(--color-primary)" : "transparent",
122	                      color: isThisAssumed ? "#fff" : "var(--color-primary)",
123	                      border: `1px solid ${isThisAssumed ? "var(--color-primary)" : "var(--color-border)"}`,
124	                    }}
125	                  >
126	                    {isThisAssumed ? "✓ Assumed" : "Assume"}
127	                  </button>
128	                )}
129	                {isConfigured && !isEditing && (
130	                  <button
131	                    onClick={() => handleStartEdit(o.id, p)}
132	                    style={{ ...actionBtnStyle, border: "1px solid var(--color-border)" }}
133	                  >
134	                    Edit
135	                  </button>
136	                )}
137	              </div>
138	
139	              {/* Inline edit slider */}
140	              {isEditing && (
141	                <div style={{ marginTop: 4, display: "flex", gap: 4, alignItems: "center" }}>
142	                  <input
143	                    type="range"
144	                    min={0.01}
145	                    max={0.99}
146	                    step={0.01}
147	                    value={editValue}
148	                    onChange={(e) => setEditValue(Number(e.target.value))}
149	                    style={{ flex: 1 }}
150	                  />
151	                  <button onClick={handleSubmitEdit} style={submitBtnStyle} disabled={mutation.isPending}>
152	                    {mutation.isPending ? "…" : "Set"}
153	                  </button>
154	                  <button onClick={() => setEditingOutcomeId(null)} style={cancelBtnStyle}>✕</button>
155	                </div>
156	              )}
157	            </div>
158	          );
159	        })}
160	      </div>
161	
162	      {mutation.isSuccess && (
163	        <div style={{ fontSize: "0.7rem", color: "var(--color-success)", marginTop: 4 }}>
164	          Edit accepted: {mutation.data.order.orderId}
165	        </div>
166	      )}
167	      {mutation.isError && (
168	        <div style={{ fontSize: "0.7rem", color: "var(--color-danger)", marginTop: 4 }}>
169	          {mutation.error instanceof Error ? mutation.error.message : "Edit failed"}
170	        </div>
171	      )}
172	    </div>
173	  );
174	}
175	
176	const rowStyle: React.CSSProperties = {
177	  padding: "var(--space-sm) var(--space-md)",
178	  borderRadius: "var(--radius-sm)",
179	  border: "1px solid var(--color-border)",
180	  background: "var(--color-bg)",
181	};
182	
183	const assumedRowStyle: React.CSSProperties = {
184	  background: "rgba(59, 130, 246, 0.04)",
185	  borderColor: "rgba(59, 130, 246, 0.2)",
186	};
187	
188	const targetRowStyle: React.CSSProperties = {
189	  borderColor: "var(--color-primary)",
190	  borderWidth: 2,
191	};
192	
193	const assumedBadge: React.CSSProperties = {
194	  fontSize: "0.65rem",
195	  fontWeight: 700,
196	  color: "var(--color-primary)",
197	  padding: "1px 6px",
198	  borderRadius: 3,
199	  background: "rgba(59, 130, 246, 0.1)",
200	};
201	
202	const actionBtnStyle: React.CSSProperties = {
203	  padding: "2px 8px",
204	  borderRadius: 3,
205	  background: "transparent",
206	  fontSize: "0.7rem",
207	  fontWeight: 500,
208	  cursor: "pointer",
209	};
210	
211	const submitBtnStyle: React.CSSProperties = {
212	  padding: "2px 10px",
213	  borderRadius: 3,
214	  border: "none",
215	  background: "var(--color-primary)",
216	  color: "#fff",
217	  fontSize: "0.7rem",
218	  fontWeight: 600,
219	  cursor: "pointer",
220	};
221	
222	const cancelBtnStyle: React.CSSProperties = {
223	  padding: "2px 6px",
224	  borderRadius: 3,
225	  border: "1px solid var(--color-border)",
226	  background: "transparent",
227	  color: "var(--color-text-muted)",
228	  fontSize: "0.7rem",
229	  cursor: "pointer",
230	};
231

